import './Positioner.scss';

import { classNames } from ':helpers/classnames';
import { getBEMClasses } from ':helpers/get-bem';
import type { PopupsContextData } from ':helpers/popupsContext';
import { PopupsContext } from ':helpers/popupsContext';
import { useDebounceCallback } from ':helpers/use-debounce-callback';
import React, { useCallback, useContext, useEffect, useLayoutEffect, useRef, useState } from 'react';

import type { PositionerProps, PositionerStyle } from './Positioner.types';

const [positionerBlock, positionerModifier] = getBEMClasses('dsb__positioner');

const defaultMinHeight = 88;

export const Positioner: React.FC<PositionerProps & { children?: React.ReactNode }> = ({
	children,
	align = 'center',
	positionerClassName,
	targetElement,
	verticalOffset = 0,
	horizontalOffset = 0,
	applicationRootElementID = 'root',
	scrollable,
	minHeight = defaultMinHeight,
}) => {
	// попробую просто переписать? Буду исходить не от Рута а от window
	const positionerRef = useRef<HTMLDivElement>(null);

	const [hasCalculatedStyle, setCalculatedStyle] = useState(false);
	const { rootElement: rootElementContext } = useContext<PopupsContextData>(PopupsContext);
	const [root, setRoot] = useState<HTMLElement | ShadowRoot>(
		rootElementContext || document.getElementById(applicationRootElementID) || document.body,
	);

	// находим root
	useLayoutEffect(() => {
		const rootElement = rootElementContext || document.getElementById(applicationRootElementID);

		if (!rootElement) {
			throw new Error(`Application root element with ID "${applicationRootElementID}" not found`);
		}

		setRoot(rootElement);
	}, [applicationRootElementID, rootElementContext]);

	// Считает и вызывает
	function calculateAndUpdate() {
		const parentRect = targetElement?.current?.getBoundingClientRect();
		if (!positionerRef.current || !parentRect) {
			return;
		}
		const style: PositionerStyle = {};
		const contentOffsetHeight = positionerRef.current.offsetHeight + verticalOffset * 2;
		const bottomSpace = window.innerHeight - parentRect.bottom;
		const positionerRect = positionerRef.current.getBoundingClientRect();
		//Позиционируем по вертикали
		if (bottomSpace > contentOffsetHeight) {
			style.top = parentRect.bottom + verticalOffset;
		} else {
			// Проверяем сверху
			if (parentRect.top > contentOffsetHeight) {
				style.bottom = window.innerHeight - parentRect.top + verticalOffset;
			} else {
				//проверяем, если сверху больше, то туда, иначе рисуем снизу ужимая
				if (parentRect.top > bottomSpace) {
					//проверяем влезит ли вообще  куда-то, если нет, то просто по краю
					if (parentRect.top > minHeight + verticalOffset * 2) {
						style.height = parentRect.top;
						style.bottom = window.innerHeight - parentRect.top + verticalOffset;
					} else {
						style.height = minHeight;
						// считаем от верхнего края, так как если не влазит, будет заходить на элемент
						style.top = verticalOffset;
					}
				} else if (bottomSpace > minHeight + verticalOffset * 2) {
					style.height = bottomSpace;
					style.top = parentRect.bottom + verticalOffset;
				} else {
					style.height = minHeight;
					// считаем от верхнего края, так как если не влазит, будет заходить на элемент
					style.bottom = verticalOffset;
				}
			}
		}

		//Позиционируем по горизонтали
		switch (align) {
			case 'center': {
				// Нужны ли здесь доп правила и урезания по ширине ? Ведь доп скролл точно не нужен...
				style.left = Math.min(
					parentRect.left + parentRect.width / 2 - positionerRect.width / 2,
					window.innerWidth - positionerRect.width - horizontalOffset,
				);
				break;
			}
			case 'left': {
				style.left = Math.min(parentRect.left, window.innerWidth - positionerRect.width - horizontalOffset);
				break;
			}
			case 'right': {
				style.left = Math.max(parentRect.right - positionerRect.width, horizontalOffset);
				break;
			}
			default: {
				//Бусть по дефолту будет слева
				style.left = Math.min(parentRect.left, window.innerWidth - positionerRect.width - horizontalOffset);
				break;
			}
		}

		applyStyle(style);
	}

	//Применение стилей
	const applyStyle = useCallback(({ position, ...pixelValues }: PositionerStyle) => {
		if (!positionerRef.current) {
			return;
		}

		const positionString = position ? `position:${position};` : '';

		const props: Array<keyof PositionerStyle> = ['top', 'left', 'right', 'bottom', 'height'];

		const sideValuesString = props
			.map((key: keyof typeof pixelValues) =>
				pixelValues[key] === undefined ? `${key}:auto;` : `${key}:${pixelValues[key]}px;`,
			)
			.join('');

		positionerRef.current.setAttribute('style', positionString + sideValuesString);

		if (!hasCalculatedStyle) {
			setCalculatedStyle(true);
		}
	}, []);

	const updatePosition = useCallback((): void => {
		calculateAndUpdate();
	}, [align, horizontalOffset, minHeight, scrollable, targetElement, verticalOffset]);

	const [debouncedUpdatePosition] = useDebounceCallback(updatePosition, 50);

	/**
	 * слушает ресайз панели
	 *
	 * нужен чтобы пересчитать позицию при изменении размеров контента
	 *
	 * например при изменении кол-ва айтемов в списке панель должна уменьшиться
	 * посути перекрывает кейсы, которые не закрывает слушатель мутации
	 */

	// useEffect(() => {
	// 	const parentMutation = new MutationObserver(debouncedUpdatePosition);

	// 	parentMutation.observe(targetElement.current, { attributes: false, childList: true, subtree: true });

	// 	return () => {
	// 		parentMutation.disconnect();
	// 	};
	// }, [targetElement]);

	/**
	 * слушает мутацию рута, обновляет позицию при изменении поддерева
	 * например нужно обновить позицию если добавится новый элемент и он сместит targetElement
	 *
	 * будут и ложные срабатывания, но сильной нагрузки не произойдет т.к работает только при открытом Positioner + есть дебаунс
	 */
	useEffect(() => {
		const parentMutation = new MutationObserver(debouncedUpdatePosition);

		parentMutation.observe(root, { attributes: false, childList: true, subtree: true });

		return () => {
			parentMutation.disconnect();
		};
	}, [root]);

	useEffect(() => {
		updatePosition();
		const disposables: Array<() => void> = [];
		const handleListener = (element: Window | Element, type: string): void => {
			element.addEventListener(type, updatePosition);
			disposables.push(() => element.removeEventListener(type, updatePosition));
		};
		handleListener(window, 'resize');
		handleListener(window, 'scroll');

		return () => {
			for (const cleanup of disposables) {
				cleanup();
			}
		};
	}, []);

	const positionerClass = classNames(
		positionerBlock,
		{
			[positionerModifier('calculating')]: !hasCalculatedStyle,
		},
		positionerClassName,
	);

	return (
		<div ref={positionerRef} className={positionerClass}>
			{children}
		</div>
	);
};
